// MARK: - Google Map View
struct DemoMapCard: UIViewRepresentable {
    func makeUIView(context: Context) -> GMSMapView {
        let camera = GMSCameraPosition.camera(withLatitude: 37.7749, longitude: -122.4194, zoom: 12.5)
        let mapView = GMSMapView(frame: .zero, camera: camera)

        mapView.settings.compassButton = true
        mapView.settings.myLocationButton = true
        mapView.isMyLocationEnabled = false

        let marker = GMSMarker()
        marker.position = CLLocationCoordinate2D(latitude: 37.7749, longitude: -122.4194)
        marker.title = "San Francisco"
        marker.snippet = "Demo Location"
        marker.map = mapView

        let marker2 = GMSMarker()
        marker2.position = CLLocationCoordinate2D(latitude: 37.8024, longitude: -122.4058)
        marker2.title = "Coit Tower"
        marker2.snippet = "Point of Interest"
        marker2.map = mapView

        return mapView
    }

    func updateUIView(_ uiView: GMSMapView, context: Context) {}
}

// MARK: - Stripe Demo ViewModel (Simulated Backend)
// This uses a local stub to create a PaymentSheet without a real server.
// It is for UI demo only and will not complete real payments.
@MainActor
final class StripeDemoViewModel: ObservableObject {
    @Published var paymentSheet: PaymentSheet?
    @Published var showingSheet: Bool = false
    @Published var statusText: String?
    @Published var isPreparing: Bool = false

    var payButtonTitle: String {
        if paymentSheet == nil { return "Loading…" }
        return "Pay $9.99"
    }

    var statusColor: Color {
        guard let statusText else { return .secondary }
        if statusText.lowercased().contains("successful") { return .green }
        if statusText.lowercased().contains("canceled") { return .orange }
        if statusText.lowercased().contains("failed") { return .red }
        return .secondary
    }

    func reset() {
        paymentSheet = nil
        statusText = nil
        showingSheet = false
        Task { await prepare() }
    }

    func prepare() async {
        guard !isPreparing else { return }
        isPreparing = true
        statusText = "Preparing PaymentSheet (demo mode)…"

        do {
            try await Task.sleep(nanoseconds: 450_000_000)

            let data = try DemoStripeBackend.createPaymentSheetConfiguration()
            var configuration = PaymentSheet.Configuration()
            configuration.merchantDisplayName = "Pitch Demo, Inc."
            configuration.allowsDelayedPaymentMethods = true
            configuration.returnURL = "demo://stripe-redirect"

            // NOTE:
            // PaymentSheet normally requires a valid client secret from your backend
            // for a PaymentIntent, SetupIntent, or CustomerSession.
            //
            // For investor UI demo without backend, we create a PaymentSheet that cannot confirm.
            // It will display but cannot complete a real payment.
            //
            // We still set it up with placeholder strings to keep the app demoable.
            paymentSheet = PaymentSheet(paymentIntentClientSecret: data.paymentIntentClientSecret, configuration: configuration)

            statusText = "Ready. Tap Pay to present the checkout UI."
        } catch {
            statusText = "Failed to prepare: \(error.localizedDescription)"
        }

        isPreparing = false
    }

    func presentPaymentSheet() {
        guard paymentSheet != nil else { return }
        statusText = nil
        showingSheet = true
    }

    func handle(result: PaymentSheetResult) {
        showingSheet = false
        switch result {
        case .completed:
            statusText = "Payment successful (demo)."
        case .canceled:
            statusText = "Payment canceled."
        case .failed(let error):
            statusText = "Payment failed: \(error.localizedDescription)"
        }
    }
}

